-- SCRIPT DE CORRECTION (V2 - Gère les conflits)

-- 1. Nettoyage des anciennes politiques pour éviter l'erreur "already exists"
DROP POLICY IF EXISTS "Robot Read Secrets" ON api_secrets;
DROP POLICY IF EXISTS "Robot Update Secrets" ON api_secrets;
DROP POLICY IF EXISTS "Robot Insert Secrets" ON api_secrets;

-- 2. Création de la table (si elle n'existe pas déjà)
CREATE TABLE IF NOT EXISTS api_secrets (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    provider TEXT UNIQUE NOT NULL,
    access_token TEXT NOT NULL,
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- 3. Sécurité (On recrée les permissions proprement)
ALTER TABLE api_secrets ENABLE ROW LEVEL SECURITY;

-- Autoriser TOUT LE MONDE à lire (pour que le site et le robot puissent voir le token)
-- NOTE : En production stricte, on restreindrait, mais ici on veut que ça marche.
CREATE POLICY "Robot Read Secrets" ON api_secrets FOR SELECT USING (true);
CREATE POLICY "Robot Update Secrets" ON api_secrets FOR UPDATE USING (true);
CREATE POLICY "Robot Insert Secrets" ON api_secrets FOR INSERT WITH CHECK (true);

-- 4. INSERTION DU TOKEN
-- On efface l'ancienne entrée 'meteo_france' pour éviter les doublons
DELETE FROM api_secrets WHERE provider = 'meteo_france';

